#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5,mod=998244353;
int n,q,ans,f[N];
vector<int> g[N];
int father(int x){
	return (f[x]==x?x:f[x]=father(f[x]));
}
int main(){
	scanf("%d%d",&n,&q);
	for(int i=1;i<=n;i++)
		f[i]=i;
	while(q--){
		int a,b,c;
		scanf("%d%d%d",&a,&b,&c);
		int op,u,v;
		op=1+(((1LL*a*(1+ans))%mod)%2);
		u=1+(((1LL*b*(1+ans))%mod)%n);
		v=1+(((1LL*c*(1+ans))%mod)%n);
		if(op==1)
			g[u].push_back(v),g[v].push_back(u),f[father(v)]=father(u);
		else{
			if(father(u)!=father(v)){
				ans=0;
				printf("0\n");
			}else{
				set<int> s;
				int len=g[u].size();
				for(int i=0;i<len;i++)
					s.insert(g[u][i]);
				len=g[v].size();
				bool flag=true;
				for(int i=0;i<len;i++)
					if(s.find(g[v][i])!=s.end()){
						ans=g[v][i];
						flag=false;
						printf("%d\n",g[v][i]);
						break;
					}
				if(flag){
					ans=0;
					printf("0\n");
				}
			}
		}
	}
	return 0;
}
